import AuditLogView from './components/AuditLogView';
import { Project } from './types';

const App: React.FC = () => {
  const [activeBug, setActiveBug] = useState<boolean>(false);
  const [currentView, setCurrentView] = useState<'home' | 'audit'>('home');
  const [selectedProject, setSelectedProject] = useState<any>(null);

  // Random bug "glitch" simulation for immersive QA theme
  useEffect(() => {
    const interval = setInterval(() => {
      if (Math.random() > 0.95) {
        setActiveBug(true);
        setTimeout(() => setActiveBug(false), 500);
      }
    }, 5000);
    return () => clearInterval(interval);
  }, []);

  const openAuditLog = (project: any) => {
    setSelectedProject(project);
    setCurrentView('audit');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const closeAuditLog = () => {
    setCurrentView('home');
    setSelectedProject(null);
  };

  if (currentView === 'audit' && selectedProject) {
    return <AuditLogView project={selectedProject} onBack={closeAuditLog} />;
  }

  return (
    <div className={`relative min-h-screen transition-all duration-300 ${activeBug ? 'blur-[1px] brightness-110' : ''}`}>
      {/* Background Orbs */}
      <div className="fixed top-[-10%] left-[-10%] w-[50%] h-[50%] bg-indigo-600/20 rounded-full blur-[120px] -z-10" />
      <div className="fixed bottom-[-10%] right-[-10%] w-[50%] h-[50%] bg-purple-600/20 rounded-full blur-[120px] -z-10" />

      <Navbar />

      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-20 space-y-32">
        <Hero />
        <QAStats />
        <BentoSkills />
        <TestReports onOpenAudit={openAuditLog} />
        <ExperienceTimeline />
      </main>

      <Footer />
      <AIQAAssistant />

      {/* Grid Pattern Overlay */}
      <div className="fixed inset-0 pointer-events-none -z-20 opacity-10" 
           style={{ backgroundImage: 'radial-gradient(circle at 2px 2px, rgba(255,255,255,0.15) 1px, transparent 0)', backgroundSize: '40px 40px' }} />
    </div>
  );
};

export default App;

