      details: "Sustained typing performance of 25 WPM with 95%+ accuracy for rapid documentation and reporting.",
      icon: <Keyboard className="w-10 h-10" />,
      color: "purple"
    }
  ];

  const nextSlide = () => {
    setActiveSlide((prev) => (prev + 1) % certifications.length);
  };

  const prevSlide = () => {
    setActiveSlide((prev) => (prev - 1 + certifications.length) % certifications.length);
  };

  useEffect(() => {
    if (isHovered || showCert) return;
    const timer = setInterval(nextSlide, 5000);
    return () => clearInterval(timer);
  }, [isHovered, showCert]);

  return (
    <div className="space-y-32">
      {/* Experience & Education Grid */}
      <section className="grid lg:grid-cols-2 gap-20">
        <div className="space-y-12">
          <h2 className="text-4xl font-display font-bold flex items-center gap-4">
            <Briefcase className="text-indigo-400" /> Career Audit
          </h2>

          <div className="space-y-8 relative before:absolute before:left-[11px] before:top-2 before:bottom-0 before:w-0.5 before:bg-white/10">
            <div className="relative pl-10">
              <div className="absolute left-0 top-1 w-6 h-6 bg-indigo-500 rounded-full border-4 border-[#030014] z-10 shadow-[0_0_15px_rgba(99,102,241,0.5)]" />
              <div className="glass-card p-6 border-white/5 hover:border-white/20 transition-all">
                <span className="text-indigo-400 text-xs font-mono mb-2 block tracking-widest uppercase">2026 – PRESENT</span>
                <h3 className="text-xl font-bold mb-1">Manual Tester (Self-Driven Projects)</h3>
                <p className="text-white/40 text-sm mb-4">Validating UX/UI and backend logic for e-commerce stacks.</p>
                <ul className="text-sm text-white/60 space-y-2">
                  <li className="flex gap-2"><span>•</span> Systematic regression testing on live builds.</li>
                  <li className="flex gap-2"><span>•</span> Detailed bug documentation using Google Sheets/Jira.</li>
                </ul>
              </div>
            </div>
