        <div className="space-y-12">
          <h2 className="text-4xl font-display font-bold flex items-center gap-4">
            <GraduationCap className="text-purple-400" /> Academic Logs
          </h2>

          <div className="space-y-8">
            <div className="glass-card p-8 border-white/5 flex gap-6 hover:bg-white/5 transition-all group">
              <div className="w-16 h-16 bg-purple-500/20 rounded-2xl flex items-center justify-center shrink-0 group-hover:scale-110 transition-transform">
                <Award className="text-purple-400" />
              </div>
              <div>
                <span className="text-purple-400 text-xs font-mono mb-1 block uppercase tracking-widest">2024 – PRESENT</span>
                <h3 className="text-xl font-bold mb-1">B.A. (Honours) – Geography</h3>
                <p className="text-white/60 text-sm italic">Jashore Govt. City College (Ongoing)</p>
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Futuristic Certificate Slider */}
      <section className="space-y-20 py-10 overflow-hidden relative">
        <div className="text-center space-y-4 relative z-10">
          <div className="inline-block px-4 py-1 bg-white/5 border border-white/10 rounded-full text-[10px] font-mono text-indigo-400 tracking-[0.3em] uppercase mb-4">
            Security Clearance Level 02
          </div>
          <h2 className="text-5xl font-display font-bold">Credential Repository</h2>
          <p className="text-white/40 max-w-xl mx-auto">Verified documentation of technical competencies and QA certifications.</p>
        </div>

        <div 
          className="relative max-w-6xl mx-auto px-4"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          {/* 3D Slider Mechanism */}
          <div className="relative h-[550px] flex items-center justify-center perspective-[2000px]">
            {certifications.map((cert, index) => {
              const isActive = index === activeSlide;
              const isPrev = index === (activeSlide - 1 + certifications.length) % certifications.length;
              const isNext = index === (activeSlide + 1) % certifications.length;

              let translateX = '0%';
              let translateZ = '0px';
              let rotateY = '0deg';
              let opacity = 0;
              let scale = 1;
              let zIndex = 0;
              let blur = '0px';

              if (isActive) {
                translateX = '0%';
                translateZ = '150px';
                opacity = 1;
                zIndex = 30;
                scale = 1.1;
              } else if (isPrev) {
                translateX = '-55%';
                translateZ = '-400px';
                rotateY = '45deg';
                opacity = 0.4;
                zIndex = 20;
                scale = 0.85;
                blur = '2px';
              } else if (isNext) {
                translateX = '55%';
                translateZ = '-400px';
                rotateY = '-45deg';
                opacity = 0.4;
                zIndex = 20;
                scale = 0.85;
                blur = '2px';
              }

              return (
                <div
                  key={cert.id}
                  onClick={() => isActive && setShowCert(cert)}
                  className={`absolute w-full max-w-2xl transition-all duration-1000 cubic-bezier(0.23, 1, 0.32, 1) cursor-pointer group`}
                  style={{
                    transform: `translateX(${translateX}) translateZ(${translateZ}) rotateY(${rotateY}) scale(${scale})`,
                    opacity: opacity,
                    zIndex: zIndex,
                    filter: `blur(${blur})`,
                    pointerEvents: opacity === 0 ? 'none' : 'auto'
                  }}
                >
                  <div className={`glass-card p-2 border-white/10 bg-white/5 shadow-[0_40px_100px_rgba(0,0,0,0.5)] relative overflow-hidden h-[450px]`}>

                    {/* Inner Content Area */}
                    <div className="relative w-full h-full bg-[#05001a] rounded-[20px] overflow-hidden flex flex-col">

                      {/* Document Preview (If image exists) */}
                      {cert.imageUrl ? (
                        <div className="relative h-2/3 w-full overflow-hidden bg-white/5 border-b border-white/10">
                          <img 
                            src={cert.imageUrl} 
                            alt={cert.title}
                            className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700 opacity-60 group-hover:opacity-90"
