                             <span className="text-[10px] font-bold uppercase tracking-widest text-white/60">Preview Mode</span>
                          </div>
                        </div>
                      ) : (
                        <div className="relative h-2/3 w-full bg-gradient-to-br from-white/5 to-transparent flex items-center justify-center group-hover:scale-105 transition-transform duration-700">
                          <div className={`p-8 rounded-full bg-white/5 border border-white/10 ${
                            cert.color === 'indigo' ? 'text-indigo-400' : cert.color === 'green' ? 'text-green-400' : 'text-purple-400'
                          }`}>
                            {cert.icon}
                          </div>
                          <div className="absolute inset-0 bg-gradient-to-t from-[#05001a] to-transparent" />
                        </div>
                      )}

                      {/* Textual Content */}
                      <div className="p-8 space-y-4 flex flex-col flex-1">
                        <div className="flex justify-between items-start">
                          <div className="space-y-1">
                            <span className={`text-[10px] font-mono uppercase tracking-[0.2em] font-bold ${
                              cert.color === 'indigo' ? 'text-indigo-400' : cert.color === 'green' ? 'text-green-400' : 'text-purple-400'
                            }`}>
                              {cert.date}
                            </span>
                            <h3 className="text-2xl font-display font-bold leading-tight group-hover:text-white transition-colors">
                              {cert.title}
                            </h3>
                          </div>
                          <div className="text-right">
                             <span className="block text-[10px] font-mono text-white/20 uppercase">ID CODE</span>
                             <span className="text-xs font-mono font-bold text-white/60">{cert.code || 'SYS-AUDIT'}</span>
                          </div>
                        </div>

                        <div className="mt-auto flex items-center justify-between">
                          <div className="flex items-center gap-3">
                            <div className="w-8 h-8 rounded-full bg-white/5 border border-white/10 flex items-center justify-center text-white/40">
                               {cert.icon}
                            </div>
                            <span className="text-sm font-bold text-white/50">{cert.issuer}</span>
                          </div>

                          <div className="flex items-center gap-2 px-4 py-2 bg-indigo-500/10 border border-indigo-500/20 rounded-xl text-indigo-400 opacity-0 group-hover:opacity-100 transition-all transform translate-y-2 group-hover:translate-y-0">
                            <ZoomIn size={16} />
