                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              );
            })}
          </div>

          {/* Nav Controls - More tactile design */}
          <div className="absolute top-1/2 -translate-y-1/2 left-0 right-0 flex justify-between pointer-events-none px-4 z-40">
            <button 
              onClick={(e) => { e.stopPropagation(); prevSlide(); }}
              className="w-14 h-14 rounded-2xl bg-[#030014]/80 border border-white/10 flex items-center justify-center text-white/40 hover:text-white hover:bg-indigo-600 hover:border-indigo-400 transition-all pointer-events-auto backdrop-blur-md shadow-2xl group/btn"
            >
              <ChevronLeft size={28} className="group-hover/btn:-translate-x-1 transition-transform" />
            </button>
            <button 
              onClick={(e) => { e.stopPropagation(); nextSlide(); }}
              className="w-14 h-14 rounded-2xl bg-[#030014]/80 border border-white/10 flex items-center justify-center text-white/40 hover:text-white hover:bg-indigo-600 hover:border-indigo-400 transition-all pointer-events-auto backdrop-blur-md shadow-2xl group/btn"
            >
              <ChevronRight size={28} className="group-hover/btn:translate-x-1 transition-transform" />
            </button>
          </div>

          {/* Progress Strip */}
          <div className="flex justify-center items-center gap-4 mt-12">
            <div className="h-0.5 w-12 bg-white/5 rounded-full overflow-hidden">
               <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${(activeSlide / (certifications.length - 1)) * 100}%` }} />
            </div>
            <div className="flex gap-2">
              {certifications.map((_, i) => (
                <button
                  key={i}
                  onClick={() => setActiveSlide(i)}
                  className={`transition-all duration-500 rounded-full ${
                    activeSlide === i ? 'w-8 h-2 bg-indigo-500' : 'w-2 h-2 bg-white/10 hover:bg-white/20'
                  }`}
                />
              ))}
            </div>
            <div className="h-0.5 w-12 bg-white/5 rounded-full overflow-hidden">
               <div className="h-full bg-indigo-500 transition-all duration-1000" style={{ width: `${100 - (activeSlide / (certifications.length - 1)) * 100}%` }} />
            </div>
          </div>
        </div>
      </section>

      {/* Detail Modal - High fidelity inspection view */}
      {showCert && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 sm:p-8">
          <div className="absolute inset-0 bg-[#030014]/98 backdrop-blur-2xl" onClick={() => setShowCert(null)} />
          <div className="relative glass-card border-white/10 max-w-5xl w-full bg-white/5 overflow-hidden flex flex-col max-h-[95vh] shadow-[0_0_150px_rgba(0,0,0,0.8)]">

