                  <img 
                    src={showCert.imageUrl} 
                    alt={showCert.title} 
                    className="w-full h-auto rounded-lg shadow-2xl border border-white/10 relative z-10"
                  />
                </div>
              ) : (
                <div className="w-full aspect-[16/10] bg-white/5 rounded-[32px] flex flex-col items-center justify-center border border-white/10 gap-6 text-center p-12 relative overflow-hidden group">
                   <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/5 via-transparent to-purple-500/5" />
                   <div className="p-8 bg-white/5 rounded-3xl text-indigo-400 shadow-2xl group-hover:scale-110 transition-transform duration-700 relative z-10">
                     {showCert.icon}
                   </div>
                   <div className="space-y-4 relative z-10">
                     <h3 className="text-4xl font-bold font-display tracking-tight">{showCert.title}</h3>
                     <p className="text-white/40 max-w-md mx-auto text-lg leading-relaxed">{showCert.details}</p>
                   </div>
                   <div className="mt-6 px-8 py-3 rounded-2xl bg-white/5 border border-white/10 text-xs font-mono uppercase tracking-[0.3em] text-white/60 relative z-10">
                     Original Document Verified via {showCert.issuer}
                   </div>
                </div>
              )}

              <div className="flex flex-col sm:flex-row items-center gap-4 pb-10 w-full justify-center">
                {showCert.validationUrl && (
                  <a 
                    href={showCert.validationUrl}
                    target="_blank"
                    rel="noreferrer"
                    className="w-full sm:w-auto px-10 py-5 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-2xl font-bold flex items-center justify-center gap-3 hover:shadow-[0_0_40px_rgba(99,102,241,0.5)] transition-all transform hover:-translate-y-1"
